sql:
SELECT label
FROM reference_types
WHERE reference_type_id = 0;

external_knowledge:
; Gauge information includes a combination of the gauge code, label, and related supplemental reference label if available; 
; The query considers only updates made within the first three days of 2022, which implies that the information is about recent changes; 
; The ordering by gauge code implies that the results are organized in a specific sequence based on the gauge codes.

sql:
SELECT COUNT(*) AS gauge_count
FROM rail_gauges
WHERE reference_type_id = 0;
